// Get today's date (just the date part, no time)
const today = new Date();
const todayDateString = today.toISOString().split('T')[0]; // Format: 2025-10-30

// Filter items where Scheduled On matches today
const filteredItems = [];

for (const item of $input.all()) {
  // Try different possible field names
  const scheduledOn = item.json['Scheduled On'] || item.json['scheduled_on'] || item.json.scheduledOn;

  console.log("Scheduled On value:", scheduledOn);
  console.log("Type:", typeof scheduledOn);

  if (scheduledOn) {
    // Extract just the date part from the scheduled value
    let scheduledDateString = '';

    if (typeof scheduledOn === 'string') {
      // Extract YYYY-MM-DD from string like "2025-10-30 10:00" or "2025-10-30 06-42"
      const dateMatch = scheduledOn.match(/(\d{4}-\d{2}-\d{2})/);
      if (dateMatch) {
        scheduledDateString = dateMatch[1];
      }
    } else if (scheduledOn instanceof Date) {
      scheduledDateString = scheduledOn.toISOString().split('T')[0];
    }

    console.log("Extracted date:", scheduledDateString);
    console.log("Matches today?", scheduledDateString === todayDateString);

    // If dates match, keep this item
    if (scheduledDateString === todayDateString) {
      filteredItems.push(item);
    }
  }
}

return filteredItems;
